const twoHoursAgo = Date.now() - (24 * 60 * 60 * 1000);
let articles = [];

for (const item of $input.all()) {
  const d = item.json;
  const keyword = d.keyword || '';
  const xmlString = d.data || '';

  if (!xmlString) continue;

  // Extract items from XML using regex
  const itemMatches = xmlString.match(/<item>([\s\S]*?)<\/item>/g) || [];

  for (const itemXml of itemMatches) {
    const getTag = (tag) => {
      const match = itemXml.match(new RegExp(`<${tag}[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\\/${tag}>|<${tag}[^>]*>([\\s\\S]*?)<\\/${tag}>`));
      return match ? (match[1] || match[2] || '').trim() : '';
    };

    const title = getTag('title');
    const link = getTag('link') || getTag('guid');
    const pubDate = getTag('pubDate');
    const ts = pubDate ? new Date(pubDate).getTime() : 0;

    if (ts > twoHoursAgo && link) {
      articles.push({ title, link, pubDate, keyword });
    }
  }
}

const seen = new Set();
articles = articles.filter(a => {
  if (!a.link || seen.has(a.link)) return false;
  seen.add(a.link);
  return true;
});

return articles.map(a => ({ json: a }));

