const { newArticles, keywords, newCount } = $json;

const articleTitles = newArticles
  .map((a, i) => `${i + 1}. [${a.keyword}] ${a.title}`)
  .join('\n');

return [{
  json: {
    articleTitles,
    keywords,
    articleCount: newCount,
    articles: newArticles
  }
}];

